// Log invoice details to a file
const fs = require('fs');
const path = '/home/hermes/hermes/scratch/briefs/biz-ops-outputs/n8n-demos/invoice-log.txt';

const invoice = items[0].json;
const logEntry = {
  timestamp: new Date().toISOString(),
  invoiceNumber: invoice.invoiceNumber || 'N/A',
  clientName: invoice.clientName || 'N/A',
  clientEmail: invoice.clientEmail || 'N/A',
  amount: invoice.amount || 0,
  currency: invoice.currency || 'USD',
  dueDate: invoice.dueDate || 'N/A',
  status: invoice.status || 'pending',
  emailSent: true
};

let logLine = JSON.stringify(logEntry) + '\n';

try {
  fs.appendFileSync(path, logLine, 'utf8');
  console.log('Invoice logged to: ' + path);
} catch (err) {
  console.error('Failed to log invoice:', err.message);
}

return items;
